// ─────────────────────────────────────────────────────────────
// Build EC Reference INSERT SQL
//
// Purpose:
// - Captures one handheld EC reference reading.
// - Stores synchronized raw and filtered voltage snapshots for:
//     A0 = KEYESTUDIO production/control channel
//     A1 = DFRobot validation/reference channel
// - Stores the current Estimated EC model output.
// - Stores tank volume, temperature, rainfall context, and operator note.
//
// Revision History:
//
// GAL 2026-07-21
// - Replaced legacy msg.tds_voltage and msg.a1_voltage properties.
// - Added separate raw and filtered A0/A1 message properties.
// - Updated SQL to use the corrected database column names:
//     a0_raw_v
//     a0_filtered_v
//     a1_raw_v
//     a1_filtered_v
// - Moved the duplicate-capture timestamp update until after validation so
//   an invalid reading does not prevent an immediate corrected retry.
//
// GAL 2026-07-20
// - Added dual conductivity-channel logging.
// - Added Estimated EC and rainfall-context capture.
// - Added 30-second duplicate submission protection.
// ─────────────────────────────────────────────────────────────

const now = Date.now();
const lastCapture =
    flow.get("outside_tds_reference_last_capture_ms") || 0;

const LOCKOUT_MS = 30000;

if (now - lastCapture < LOCKOUT_MS) {
    node.warn(
        `Ignored duplicate EC reference capture inside ` +
        `${LOCKOUT_MS / 1000} second lockout.`
    );
    return null;
}

/**
 * Convert a Home Assistant state or formatted value into a finite number.
 *
 * Returns null for:
 * - Missing values
 * - Empty strings
 * - unknown
 * - unavailable
 * - none
 * - null
 * - Non-numeric values
 */
function cleanNumber(value) {
    if (value === undefined || value === null) {
        return null;
    }

    const text = String(value).trim().toLowerCase();

    if (
        text === "" ||
        text === "unknown" ||
        text === "unavailable" ||
        text === "none" ||
        text === "null"
    ) {
        return null;
    }

    const numberValue =
        parseFloat(String(value).replace(/[^0-9.\-]/g, ""));

    return Number.isFinite(numberValue)
        ? numberValue
        : null;
}

/**
 * Safely format optional text for a MariaDB SQL statement.
 *
 * Empty or missing text is stored as SQL NULL.
 * Single quotes are escaped for MariaDB.
 * Text is limited to 255 characters.
 */
function sqlText(value) {
    if (value === undefined || value === null) {
        return "NULL";
    }

    const text = String(value).trim();

    if (text.length === 0) {
        return "NULL";
    }

    return "'" +
        text
            .replace(/'/g, "''")
            .slice(0, 255) +
        "'";
}

/**
 * Format an optional number for SQL.
 *
 * Invalid or unavailable values are stored as SQL NULL.
 */
function sqlNumber(value, decimals) {
    return value === null
        ? "NULL"
        : value.toFixed(decimals);
}

// ─────────────────────────────────────────────────────────────
// Conductivity voltage snapshots
//
// These message-property names describe the engineering meaning and are
// intentionally independent of the current Home Assistant entity IDs.
// ─────────────────────────────────────────────────────────────

const a0RawV =
    cleanNumber(msg.a0_raw_v);

const a0FilteredV =
    cleanNumber(msg.a0_filtered_v);

const a1RawV =
    cleanNumber(msg.a1_raw_v);

const a1FilteredV =
    cleanNumber(msg.a1_filtered_v);

// ─────────────────────────────────────────────────────────────
// Engineering and operator reference values
// ─────────────────────────────────────────────────────────────

const estimatedEc =
    cleanNumber(msg.estimated_ec);

const meterValue =
    cleanNumber(msg.meter_value);

const gallons =
    cleanNumber(msg.tank_gallons);

const waterTemp =
    cleanNumber(msg.water_temp_f);

// ─────────────────────────────────────────────────────────────
// Rainfall and exposed-reservoir context
// ─────────────────────────────────────────────────────────────

const rainTotal =
    cleanNumber(msg.rain_total_in);

const previousRain =
    cleanNumber(msg.previous_rain_total);

const tankLength =
    cleanNumber(msg.tank_length_in);

const tankWidth =
    cleanNumber(msg.tank_width_in);

const captureFactor =
    cleanNumber(msg.rain_capture_factor) ?? 1.0;

const units =
    String(msg.meter_units || "EC").trim();

const note =
    msg.reference_note;

let rainSince = null;
let rainAddedGallons = null;

if (
    rainTotal !== null &&
    previousRain !== null &&
    tankLength !== null &&
    tankWidth !== null
) {
    rainSince =
        Math.max(0, rainTotal - previousRain);

    rainAddedGallons =
        rainSince *
        tankLength *
        tankWidth /
        231 *
        captureFactor;
}

// ─────────────────────────────────────────────────────────────
// Required measurement validation
//
// All four voltage snapshots are required for new reference records.
// This prevents partially populated calibration records from being written.
// ─────────────────────────────────────────────────────────────

if (a0RawV === null) {
    node.error(
        "EC reference capture failed: invalid A0 raw voltage.",
        msg
    );
    return null;
}

if (a0FilteredV === null) {
    node.error(
        "EC reference capture failed: invalid A0 filtered voltage.",
        msg
    );
    return null;
}

if (a1RawV === null) {
    node.error(
        "EC reference capture failed: invalid A1 raw voltage.",
        msg
    );
    return null;
}

if (a1FilteredV === null) {
    node.error(
        "EC reference capture failed: invalid A1 filtered voltage.",
        msg
    );
    return null;
}

if (meterValue === null || meterValue <= 0) {
    node.error(
        "EC reference capture failed: handheld meter value is missing or invalid.",
        msg
    );
    return null;
}

// Validation passed. Start the duplicate-capture lockout now so a failed
// validation does not block an immediate corrected capture.
flow.set(
    "outside_tds_reference_last_capture_ms",
    now
);

// ─────────────────────────────────────────────────────────────
// Build MariaDB INSERT
// ─────────────────────────────────────────────────────────────

msg.topic = `
INSERT INTO hydro_tds_reference_reading
    (
        system_key,
        a0_raw_v,
        a0_filtered_v,
        a1_raw_v,
        a1_filtered_v,
        estimated_ec,
        meter_value,
        meter_units,
        tank_gallons,
        water_temp_f,
        rain_total_in,
        rain_since_last_reference_in,
        estimated_rain_added_gal,
        note
    )
VALUES
    (
        'outside',
        ${a0RawV.toFixed(3)},
        ${a0FilteredV.toFixed(3)},
        ${a1RawV.toFixed(3)},
        ${a1FilteredV.toFixed(3)},
        ${sqlNumber(estimatedEc, 2)},
        ${meterValue.toFixed(2)},
        ${sqlText(units)},
        ${sqlNumber(gallons, 2)},
        ${sqlNumber(waterTemp, 1)},
        ${sqlNumber(rainTotal, 3)},
        ${sqlNumber(rainSince, 3)},
        ${sqlNumber(rainAddedGallons, 3)},
        ${sqlText(note)}
    );
`;

// Structured engineering snapshot for debugging and downstream nodes.
msg.payload = {
    system_key: "outside",

    // KEYESTUDIO production/control channel.
    a0_raw_v: a0RawV,
    a0_filtered_v: a0FilteredV,

    // DFRobot validation/reference channel.
    a1_raw_v: a1RawV,
    a1_filtered_v: a1FilteredV,

    estimated_ec: estimatedEc,
    meter_value: meterValue,
    meter_units: units,
    tank_gallons: gallons,
    water_temp_f: waterTemp,
    rain_total_in: rainTotal,
    rain_since_last_reference_in: rainSince,
    estimated_rain_added_gal: rainAddedGallons,
    note: note
};

return msg;
